INSERT INTO `careers` (`id`, `career_name`, `career_type`, `career_skill_one`, `career_skill_two`, `career_skill_three`, `career_gift_one`, `career_gift_one_choice`, `career_gift_two`, `career_gift_two_choice`, `career_gift_three`, `career_gift_three_choice`, `career_source_book`, `pg_no`, `career_archtype`, `career_description`, `career_trappings`, `requires`) VALUES
(1, 'Almoner', 1, 1, 12, 21, 14, NULL, 15, 'Calabrese', 16, NULL, 5, 33, 7, 'A practitioner of White Magic who has devoted their life to charity, using supernatural power to heal others.', 'Electrum Rod (Damage +2, Parry d12), Leather armor (d6), knife, first aid kit, holy vestments, holy symbol', NULL),
(2, 'Apothecary', 2, 1, 9, 10, 46, NULL, 15, 'Calabrese', 31, NULL, 5, 279, 1, 'A chemist who sells medicine, usually proscribed by a doctor with more training, found only in large villages, sometimes as a hermit in the woods.', 'Knife, first aid kit, writing kit', NULL),
(3, 'Artist', 2, 1, 9, 10, 47, NULL, 32, NULL, 15, 'Calabrese', 5, 279, 1, 'Constantly searching for rich patrons to fund their projects, the Artist must balance their muse with their next pay.', 'Knife, makeup', NULL),
(4, 'Bandit', 2, 13, 20, 23, 21, NULL, 19, NULL, 27, NULL, 5, 279, 4, 'A criminal who joins a gang to mug people and take their valuables.', 'Mace (Damage +2), Leather armor (d6), large sack', NULL),
(5, 'Barber', 2, 1, 9, 10, 48, NULL, 46, NULL, 15, 'Calabrese', 5, 279, 1, 'Not just a groomer, the Barber also provides dentistry and basic first-aid. Any decently - sized village has one.', '2 Daggers (Damage +1), Cloth armor (d4), shears, tongs', NULL),
(6, 'Bawd', 1, 5, 9, 14, 17, NULL, 18, NULL, 19, NULL, 5, 33, 4, 'Sometimes called a \"procurer\" or \"hustler\", a good Bawd knows where all the dirty goings-on in the city are, and is willing to entertain ... For a price.', 'Shortsword (Damage +1 Impaling), Leather armor (d6), dagger, cheap make-up, cheap cologne', NULL),
(7, 'Begger (Calabria)', 2, 14, 15, 20, 49, NULL, 19, NULL, 94, NULL, 5, 279, 4, 'A pitiable sort who lives hand to mouth, a Beggar is always looking for junk or for information to sell.', 'Staff (Damage +1, Parry d12), Cloth armor (d4), bowl, religious symbol, crutch', NULL),
(8, 'Bodyguard', 1, 2, 10, 15, 20, NULL, 98, NULL, 21, NULL, 5, 33, 6, 'A bouncer or attendant, a Bodyguard must be willing to take a bullet for their charge.', 'Staff (Damage +1, Parry d12), Leather armor (d6), dagger, rope', NULL),
(9, 'Bounty-Hunter', 1, 2, 13, 19, 21, NULL, 64, NULL, 96, NULL, 5, 33, 6, 'A thief-taker who finds people and then brings them back alive for a reward.', 'Mace (Damage +2), Sling (Damage +0), Leather armor (d6), dagger, large sack, small sack, rope', NULL),
(10, 'Burglar', 1, 3, 19, 20, 107, NULL, 64, NULL, 19, NULL, 5, 33, 4, 'Someone who breaks and enters to steal valuables, a Burglar is sometimes called a \"wall-breaker\" or \"second-story man\".', 'Shortsword (Damage +1 Impaling), Leather armor (d6), large sack, small sack, dagger, lockpicks, knife', NULL),
(11, 'Cavalier', 2, 12, 13, 18, 50, NULL, 26, NULL, 51, NULL, 5, 279, 5, 'A mounted fighter, a leader o soldiers, the Cavalier is a champion of their lord and fight in their name.', 'Lance, Longsword (Damage +2), shield (Cover d8), Leather armor (d6), knife, banner with coat of arms', NULL),
(12, 'Champion', 2, 2, 7, 13, 34, NULL, 52, NULL, 27, NULL, 5, 280, 6, 'An honorable warrior who fights in trials-by-combat or in wartime, in service to their lord or lady.', 'Longsword (Damage +2), Wooden Shield (Cover d8), Sling (Damage +1), dagger, tabard', NULL),
(13, 'Charlatan', 1, 5, 14, 16, 23, NULL, 24, NULL, 19, NULL, 5, 34, 4, 'A con artist, often disguised as a doctor or a mystic, the Charlatan peddles useless charms and quack medicine to the rubes', 'Trappings: Shortsword (Damage +1 Impaling), Leather armor (d6), dagger, cheap make-up, spare clothes', NULL),
(14, 'Clown', 2, 7, 11, 16, 77, NULL, 113, NULL, 112, NULL, 2, 352, 2, 'Often works as a street performer.', 'Cloth armor (d4), marotte, motley outfit, random items to juggle', NULL),
(15, 'Coachman', 2, 15, 18, 25, 53, NULL, 36, NULL, 54, NULL, 5, 280, 3, 'Driving the passenger wagons along the roads, Coachmen live in fear of bandit gangs and highwaymen.', 'Shortsword (Damage +1 Impaling), Lever Crossbow (Damage +1), Leather Armor (d6), knife, riding crop', NULL),
(16, 'Craftsman', 2, 4, 10, 14, 55, NULL, 33, NULL, 3, NULL, 5, 280, 3, 'A skilled laborer, a Craftsman may either have a local shop or be a traveller looking for work.', 'Shortsword (Damage +1 Impaling), knife, tools', NULL),
(17, 'Dilettante', 1, 9, 10, 14, 25, NULL, 15, 'Calabrese', 26, NULL, 5, 34, 5, 'A ne\'er-do-well who avoids work by spending the family fortune, the dilettante can get mixed up in all kinds of affairs.', 'Pistol (Spark d10, Damage +2 Slaying), Rapier (Damage +2 Impaling), Leather Armor (d6), dagger, hat, cape, signet ring', NULL),
(18, 'Diplomat', 2, 10, 12, 14, 56, NULL, 15, 'Calabrese', 26, NULL, 5, 280, 5, 'A negotiator who travels into rival demesne, the Diplomat parleys hostage releases and land disputes.', 'Shortsword (Damage +1 Impaling), Cloth armor (d4), letter of patent of nobility, signet ring, white flag', NULL),
(19, 'Dopplesoldner', 1, 7, 8, 13, 21, NULL, 81, NULL, 27, NULL, 5, 34, 6, 'A front-line soldier who specializes in two-handed weapons and great strength.', 'Greatsword (Damage +3), Sling (Damage +0), Leather armor (d6), knife, hat', NULL),
(20, 'Elementalist', 1, 1, 15, 21, 28, 'Star', 29, NULL, 15, 'Calabrese', 5, 34, 7, 'Trained in the Dunwasser philosophy, an Elementalist has supernatural command over the natural elements.', 'Dioptra Rod (Damage +2, Parry d12), Leather armor (d6), knife, first aid kit', NULL),
(21, 'Engineer', 2, 1, 4, 6, 30, NULL, 15, 'Calabrese', 57, NULL, 5, 280, 1, 'Trained in physics and math, the Engineer is needed to design the grand architecture used in civil buildings and modern warfare.', 'Knife, Leather armor (d6), plum-bob, square, compass', NULL),
(22, 'Entertainer', 2, 5, 9, 16, 17, NULL, 23, NULL, 110, NULL, 5, 280, 3, 'Actor, singer, clown, bard - everyone needs a little joy in their life.', 'Shortsword (Damage +1 Impaling), knife, makeup', NULL),
(23, 'Explorer', 1, 1, 8, 19, 30, NULL, 15, 'Calabrese', 31, NULL, 5, 34, 1, 'A brave soul who looks to carve a new path through the wilderness, an Explorer needs both their health and their wits to survive.', 'Shortsword (Damage +1 Impaling), Leather armor (d6), dagger, undecipherable map to unknown place', NULL),
(24, 'Farmer', 2, 4, 8, 26, 55, 'Farming', 53, NULL, 3, NULL, 5, 281, 3, 'Four out of five people in Calabria are simple Farmers who till the land from before sunrise until after sunset.', 'Pitchfork (Damage +2), knife, large sack', NULL),
(25, 'Fence', 2, 5, 10, 14, 24, NULL, 33, NULL, 19, NULL, 5, 281, 4, 'A buyer and seller of stolen goods, Fences run the black markets, where they meet with all kinds of scoundrels, cut-throats, and rebels.', 'Shortsword (Damage +1 Impaling), Leather armor (d6), knife, large sack, purse', NULL),
(26, 'Functionary', 2, 1, 10, 14, 58, NULL, 70, NULL, 15, 'Calabrese', 5, 281, 1, 'Empires don\'t run themselves. Functionaries are career bureaucrats who work in the larger administrations. ', 'Knife, Cloth armor (d4), inkwell, pen, stamp', NULL),
(27, 'Gambler', 2, 9, 10, 15, 17, NULL, 71, NULL, 19, NULL, 5, 281, 4, 'A professional player of dice or card games, Gamblers live for today, hand-to-mouth, trusting in their luck.', 'Shortsword (Damage +1 Impaling g), Leather armor (d6), dagger, good luck charm', NULL),
(28, 'Haranguer', 2, 9, 10, 16, 77, NULL, 68, NULL, 112, NULL, 2, 352, 2, 'A trouble-maker who rouses the rabble against the status quo.', 'Leather Armor (d6), Dagger (Dama e +1), effigy, list of public grievances', NULL),
(29, 'Herbalist', 2, 1, 6, 19, 15, 'Calabrese', 72, NULL, 96, NULL, 5, 281, 1, 'A humble practitioner of folk medicine, the Herbalist is often the only healer to be found in small villages.', 'Knife, Cloth armor (d4), shovel, seeds', NULL),
(30, 'Highwayman', 2, 13, 16, 18, 25, NULL, 51, NULL, 19, NULL, 5, 281, 4, 'The Highwayman lives a double life: respectable citizen by day, thief by night. They specialize in flashy clothes and daring escapes.', 'Pistol (Spark d10, Damage +2 Slaying), Rapier (Damage +2 Impaling), Leather armor (d6), Palfrey, hat, cape, mask', NULL),
(31, 'Hobgoblin', 2, 5, 16, 24, 77, NULL, 63, NULL, 112, NULL, 2, 352, 2, 'Nicknamed after an obsessive (but imagined) fear, the Hobgoblin is an assassin who hides in plain sight, as a clown.', 'Leather armor (d6), three juggling Daggers (Damage +1), three juggling balls (Damage +0)', NULL),
(32, 'Hunter', 2, 8, 17, 19, 97, NULL, 94, NULL, 96, NULL, 5, 282, 3, 'Trapping and shooting animals for subsistence and for sale, many Hunters are illegally poaching on a lord', 'Sling (Damage +1), Shortbow (Damage +0 Impaling), Shortsword (Damage +1 Impaling), Leather armor (d6), knife', NULL),
(33, 'Itinerant Fool', 2, 7, 8, 16, 77, NULL, 112, NULL, 44, NULL, 2, 352, 2, 'No doubt you\'re on some dread errand. Even less doubt that you won\'t succeed.', 'Leather Armor (d6), Staff (Damage +1, Parry d12), bindle, pointy shoes', NULL),
(34, 'Jailer', 2, 2, 13, 15, 59, NULL, 9, NULL, 21, NULL, 5, 282, 6, 'In Calabria, prisons are a temporary affair, used only to hold nobles traded for ransom and slaves sold into indenture.', 'Staff (Damage +1, Parry d12), Lever Crossbow ( damage +1), dagger, manacles, key ring', NULL),
(35, 'Jester', 2, 9, 10, 16, 77, NULL, 112, NULL, 32, NULL, 2, 352, 2, 'An entertainer to the royal court. And sometimes an advisor. And sometimes, a spy.', 'Cloth armor (d4), pamphlet of salacious ribaldry', NULL),
(36, 'Jinxter', 2, 7, 16, 21, 77, NULL, 112, NULL, 15, 'Calabrese', 2, 353, 2, 'A dabbler in the wizardly arts, who is more effective at berating people than bewitching them.', 'Cloth Armor (d4), Staff (Damage +1, Parry d12), pointy hat', NULL),
(37, 'Knight-Errant', 1, 7, 13, 23, 32, NULL, 26, NULL, 27, NULL, 5, 34, 5, 'Failing fortunes have made this brave and blooded warrior become a sell-sword so they can pay the bills.', 'Longsword (Damage +2), Shortbow (Damage +0 Critical), Wooden Shield (Cover d8), Leather armor (d6), signet ring', NULL),
(38, 'Marauder', 2, 13, 17, 18, 51, NULL, 21, NULL, 27, NULL, 5, 282, 6, 'A fearsome plunderer, the Marauder rides in, takes all that they can, and burns the rest.', 'Longsword (Damage +2), Wooden shield (Cover d8), Lever Crossbow (Damage +1), dagger, destrier', NULL),
(39, 'Marine', 2, 13, 17, 22, 21, NULL, 60, NULL, 27, NULL, 5, 282, 6, 'The marines who fight for us, we call \"privateers\". The marines who fight for themselves we call \"pirates\".', 'Shortsword (Damage +1 Impaling), Buckler (Cover d4), Lever Crossbow (Damage +1), dagger, rope', NULL),
(40, 'Mercenary', 1, 7, 13, 17, 33, NULL, 21, NULL, 27, NULL, 5, 35, 6, 'Sometimes called a \"white shields\" or \"sell-sword\", a mercenary works odd jobs for money, trying to balance risk and payoff.', 'Longsword (Damage +2), Shortbow (Damage +0 Critical) Wooden Shield (Cover d8), Leather armor (d6), dagger', NULL),
(41, 'Merchant', 2, 9, 10, 14, 56, NULL, 37, NULL, 33, NULL, 5, 282, 3, 'A buyer and seller of legitimate goods, adventurers will interact with Merchants quite a bit.', 'Shortsword (Damage +1 Impaling), Leather armor (d6), knife, purse, strongbox for money', NULL),
(42, 'Messenger', 1, 8, 9, 15, 35, NULL, 36, NULL, 97, NULL, 5, 35, 3, 'From the pages who carry notes inside the cities, to the letter-carriers who hike along the roads, Messengers are everywhere people are.', 'Shortsword (Damage +1 Impaling), Sling (Damage +0), Leather armor (d6), dagger', NULL),
(43, 'Militiaman', 2, 4, 13, 24, 55, NULL, 21, NULL, 27, NULL, 5, 282, 6, 'In the disputed territories, the locals must defend themselves.\nThe Militiaman splits their time between fighting and working.', 'Spear (Damage +3), Javelin (Damage +1), Lever Crossbow (Damage +1), Cloth armor (d4), dagger, destrier', NULL),
(44, 'Mime', 2, 7, 16, 20, 77, NULL, 112, NULL, 49, NULL, 2, 353, 2, 'A fool who specializes in silent pantomime.', 'Cloth armor (d4), makeup, invisible box, invisible rope', NULL),
(45, 'Navigator', 2, 1, 15, 26, 61, NULL, 30, NULL, 15, 'Calabrese', 5, 283, 1, 'Indispensable for those long sea voyages, the Navigator uses star charts and world maps to plot courses over the ocean blue.', 'Knife, Cloth armor (d4), sextant', NULL),
(46, 'Naybob', 2, 7, 15, 16, 77, NULL, 112, NULL, 98, NULL, 2, 353, 2, 'This fool\'s constant negative approach to life would be more annoying ... If they weren\'t so often right.', 'Leather armor (d6), Dagger (Damage +1), useless good- luck charm, second useless good-luck charm', NULL),
(47, 'Ostler', 2, 18, 25, 26, 53, NULL, 3, '54', 91, NULL, 5, 283, 3, 'An innkeeper, tavern-owner, or lowly stablehand, an Ostler works with travellers to provide room and board, and to maintain their animals and vehicles.', 'Pitchfork (Damage +2), Leather armor (d6), knife', NULL),
(48, 'Outlaw', 2, 7, 17, 20, 21, NULL, 19, NULL, 27, NULL, 5, 283, 4, 'Sniping from a distance, then looting the body ', 'Longbow (Damage +1), Leather armor (d6), knife, large sack', NULL),
(49, 'Paladin', 1, 1, 13, 21, 38, NULL, 15, 'Calabrese', 16, NULL, 5, 35, 7, ' Sometimes called \"the first of god\" the paladin devotes their life to fighting with sword and with spell against the supernatural forces of evil.', 'Calendar Sword (Damage +2), Wooden Shield (Cover d8), Leather Armor (d6), dagger. holy symbol, bible', NULL),
(50, 'Patsy', 2, 7, 12, 16, 77, NULL, 112, NULL, 7, NULL, 2, 353, 2, 'This person only thinks they\'re in charge, but they\'ve been set up to take the fall for another noble, crime lord, or boss. ', 'Leather armor (d6), Shortsword (Damage +1 Impaling), Wooden Shield (Cover d8), incriminating evidence', NULL),
(51, 'Peddler', 2, 4, 8, 14, 55, NULL, 33, NULL, 62, NULL, 5, 283, 3, 'Pushing a cart and hawking their wares, a Peddler scavenges junk or makes handicrafts, then sells them for money.', 'Mace (Damage +2), Leather armor (d6), knife, cart, junk', NULL),
(52, 'Physician', 2, 1, 10, 15, 48, NULL, 15, 'Calabrese', 72, NULL, 5, 283, 1, 'A professional doctor or surgeon, the Physician is classically trained in anatomy and physiology.', 'Knife, Cloth armor (d4), bonesaw', NULL),
(53, 'Picaro', 2, 7, 15, 16, 77, NULL, 112, NULL, 19, NULL, 2, 353, 2, 'A low-class, humorous fellow who lives by their wits among the dishonest and the fraudulent.', 'Leather armor (d6), Mace (Damage +2), Wooden Shield (Cover d8), knife, first aid kit, wineskin with cheap wine', NULL),
(54, 'Pickpocket', 2, 5, 9, 20, 63, NULL, 64, NULL, 19, NULL, 5, 283, 4, 'A light-fingered cut-purse, the Pickpocket specializes in bumping into people and ripping off their valuables', 'Shortsword (Damage +1 Impaling g), Cloth armor (d4), someone else', NULL),
(55, 'Pit Fighter', 1, 2, 7, 13, 34, NULL, 21, NULL, 27, NULL, 5, 35, 6, 'A ruthless gladiator who does battle for other', 'Mace (Damage +2), Leather armor (d6), dagger, bandages', NULL),
(56, 'Poltroon', 2, 7, 13, 16, 77, NULL, 112, NULL, 27, NULL, 2, 353, 2, 'Often petty and mean-spirited, this warrior is much better at enraging their foes than engaging them.', 'Leather & Cloth Armor (d6, d4), Bastard Sword (Damage +4, Awkward), Wooden Shield (Cover d8)', NULL),
(57, 'Priest or Priestess', 2, 1, 4, 8, 46, NULL, 15, 'Calabrese', 65, NULL, 5, 284, 1, 'A humble believer, either sequestered far away from the lay folk or doing the great work in churches big or small.', 'holy symbol, holy book', NULL),
(58, 'Rake', 1, 7, 9, 14, 17, NULL, 37, NULL, 19, NULL, 5, 35, 4, 'A rogue who enjoys a good time, the Rake must move quickly to always be one step ahead of their creditors.', 'Shortsword (Damage +1 Impaling), Leather armor (d6), dagger, hat, cape', NULL),
(59, 'Ranger', 1, 7, 8, 17, 34, NULL, 21, NULL, 27, NULL, 5, 35, 6, 'Patrolling large swaths of forest and plains, Rangers bring law to the lawless and hope to the hopeless.', 'Longbow (Damage +1 Critical), Shortsword (Damage +1 Impaling), Leather armor (d6), dagger, 7-league boots', NULL),
(60, 'Robber', 2, 2, 13, 20, 21, NULL, 19, NULL, 27, NULL, 5, 284, 4, 'Also called a footpad or a bravo, the Robber is a sneaky, solitary sort, who violently blind- sides victims and takes their valuables.', 'Mace (Damage +2), Cloth armor (d4), large sack', NULL),
(61, 'Sailor', 2, 22, 25, 26, 17, NULL, 60, NULL, 3, NULL, 5, 284, 3, 'Another hand on the deck of a frigate or other sailing ship, a Sailor travels the world.', 'Dagger (Damage +1), Leather armor (d6), rope', NULL),
(62, 'Scholar', 2, 1, 10, 21, 212, NULL, 15, 'Calabrese', 31, NULL, 5, 285, 1, 'A learned person, librarian, or advisor, a Scholar will need a wealthy patron to pay their wages.', 'Knife, Cloth armor (d4), bookmark', NULL),
(63, 'Scout', 1, 8, 15, 20, 35, NULL, 97, NULL, 21, NULL, 5, 36, 6, 'Advanced lookouts who take the point, then report back what they see, there are two kinds of Scouts ', 'Sling (Damage +0), Shortsword (Damage +1 Impaling), Wooden shield (Cover d8), dagger', NULL),
(64, 'Seer', 2, 1, 16, 21, 15, NULL, 68, NULL, 31, NULL, 5, 285, 1, 'Someone who claims the ability to see into the future, a Seer may be a local nut, or they may be a respected prophet.', 'Staff (Damage +1, Parry d12), Cloth armor (d4), hooded shroud, strange jewellery', NULL),
(65, 'Servant', 2, 9, 10, 14, 32, NULL, 49, NULL, 3, NULL, 5, 284, 3, 'A humble attendant to an aristocrat, a Servant tends to the daily affairs.', 'Dagger (Damage +1), servant', NULL),
(66, 'Slaver', 2, 2, 13, 23, 66, NULL, 21, NULL, 27, NULL, 5, 284, 6, 'A warrior who captures people, takes them abroad, and sells them for money, the Slavers are the scourge of the badlands.', 'Goad (Damage +2), Leather armor (d6 ), knife, rope, net, large sack, small sack', NULL),
(67, 'Snitch', 2, 9, 10, 15, 49, NULL, 64, NULL, 19, NULL, 5, 285, 4, 'Someone who eavesdrops on others, hoping to sell the information later, the job of the Snitch can be a dangerous career', 'Mace (Damage +2), Cloth armor (d4), large sack', NULL),
(68, 'Soldier', 1, 13, 17, 23, 97, NULL, 21, NULL, 27, NULL, 5, 36, 6, 'Whether it\'s for king or for country, the soldier marches many miles and then fights alongside comrades. ', 'Longbow (Damage +1 Critical), Longsword (Damage +2), Wooden shield (Cover d8), Leather Armor (d6), old uniform', NULL),
(69, 'Sorcerer', 1, 1, 10, 21, 39, NULL, 40, NULL, 15, 'Calabrese', 5, 36, 7, 'A sly wizard who learns the mysterious \"Green & Purple Magic\" to tap into the minds of others and learn their secrets. ', 'Quicksilver Rod (Damage +2, Parry d12), Leather armor (d6), Green Robe, Olive Wand, Tourmaline Headband', NULL),
(70, 'Spellbinder', 1, 1, 14, 21, 41, NULL, 40, NULL, 15, 'Calabrese', 5, 36, 7, 'A fearsome wizard who uses \"Green & Purple Magic\" to control weaker minds.', 'Quicksilver Rod (Damage +2, Parry d12), Leather armor (d6), Green Robe, Olive Wand, Tourmaline Headband', NULL),
(71, 'Spy', 2, 2, 13, 23, 23, NULL, 49, NULL, 67, NULL, 5, 284, 4, 'An illicit observer for some other agency, a Spy must maintain a real job while they pass information to their master ', 'Pistol (Damage +2 Slaying), Stiletto (Damage +2 Impaling), several outfits', NULL),
(72, 'Stooge', 2, 7, 10, 16, 77, NULL, 112, NULL, 76, NULL, 2, 353, 2, 'An underling whose wit can serve as a distraction.', 'Leather armor (d6), Mace (Damage +2), Wooden shield (Cover d8), knife, first aid kit, ridiculous hat', NULL),
(73, 'Thaumaturge', 1, 1, 15, 21, 42, NULL, 43, NULL, 15, 'Calabrese', 5, 36, 7, 'A humble wizard of Thaumaturgy, the mysterious and purest form of magic.', 'Longsword (Damage +2), Wooden Shield (Cover d8),Leather armor (d6), dagger, divining rod', NULL),
(74, 'Town Fool', 2, 9, 16, 19, 77, NULL, 112, NULL, 17, NULL, 2, 353, 2, 'Hark! The village has called. It seems they\'re missing their local idiot.', 'Cloth armor (d4), three shiny rocks, bucket with a hole', NULL),
(75, 'Vagabond', 1, 8, 9, 15, 17, NULL, 44, NULL, 19, NULL, 5, 36, 4, 'A carefree wanderer out to see the world, the Vagabond talks to everyone as they seek out adventure in all corners.', 'Mace (Damage +2), Cloth armor (d4), large sack', NULL),
(76, 'Warlock (Air)', 1, 7, 13, 21, 45, 'Air', 29, NULL, 15, 'Calabrese', 5, 36, 7, 'A wizard who has passed over theory and philosophy to train to use elemental magic for battle.', 'Shortsword (Damage +1 Impaling), Leather armor (d6)', NULL),
(77, 'Watchman', 2, 13, 15, 19, 69, NULL, 21, NULL, 27, NULL, 5, 285, 6, 'In the larger towns and cities, the Watchmen patrol the streets and bring law to the criminals.', 'Iron Staff (Damage +2), Sling (Damage +1), Leather armor (d6), knife, rope, uniform, badge', NULL),
(78, 'Witch Finder', 2, 13, 19, 21, 15, 'Calabrese', 42, NULL, 43, NULL, 5, 285, 7, 'A brazen wizard who has studied Thaumaturgy, to find evidence of magic and to fight other wizards.', 'Cypress Rod (Damage +2, Parry d12), Lever Crossbow (Damage +1), Leather armor (d6), dagger, divining rod', NULL),
(79, 'Worker', 2, 2, 4, 8, 17, NULL, 81, NULL, 3, NULL, 5, 285, 3, 'First toil, then the grave! Workers can be found at construction sites, dockyards, or any place where there', 'Club (Damage +1), Cloth armor (d4), knife, large sack', NULL),
(80, 'Admiralty Captain', 1, 1, 12, 25, 26, NULL, 7, NULL, 27, NULL, 1, 910, 5, 'You\'ve been trained by your king and country to lead a ship to victory. Try not to let your well-heeled breeding go to your head, you\'e in foreign waters.', 'Short Sword, Leather Armor', NULL),
(81, 'Balian', 1, 1, 12, 21, 381, NULL, 273, 'Tawas', 176, NULL, 1, 910, 7, 'This practitioner always uses female pronouns. One who was born female is also called baliana; otherwise, they may be called asog. They are sought out to help with supernatural matters', 'Cassia Rod, Pesisir Robe', NULL),
(82, 'Boatswain', 1, 4, 15, 25, 33, NULL, 60, NULL, 3, NULL, 1, 911, 3, 'Someone needs to be looking out for the welfare of the ship, and that\'s you. You\'re in charge of repairs and maintenance.', 'Shortsword, Leather Armor', NULL),
(83, 'Cannoneer', 1, 15, 23, 25, 60, NULL, 3, NULL, 7, NULL, 1, 911, 3, 'Loading, aiming, and firing a cannon is a team job. They need someone like you who can coordinate all the steps for maximum accuracy and rate of fire', 'Shortsword, Leather Armor', NULL),
(84, 'Catalonan', 1, 1, 14, 21, 273, 'Tawas', 282, NULL, 385, NULL, 1, 911, 7, 'Most catalonans are older people, wearing a mix of male and female clothing. Their age and lack of fecundity is said to allow them to talk to spirits of all genders.', 'Yakal Rod, Ciberon Robe', NULL),
(85, 'Dalagangan', 1, 1, 21, 26, 273, 'Tawas', 282, NULL, 385, NULL, 1, 911, 7, 'An adept of basic magics is also called the pawang huian or rain wizard. The more-accomplished dalagangans can command the weather or call down disasters', 'Yakal Rod, Cirebon Robe', NULL),
(86, 'Diver', 1, 8, 15, 22, 34, NULL, 155, NULL, 103, NULL, 1, 912, 3, 'Shells, amber, pearls, and other items on the sea floor can be collected and sold.', 'Dagger, Kelp Armor', NULL),
(87, 'Fernwehner', 1, 1, 9, 10, 146, NULL, 276, NULL, 60, NULL, 1, 912, 7, 'Sometimes a child is born who hears the calling of far-away spirts. But no matter how far they travel, they always want to go further. (This career requires Book of Mysteries.)', 'Staff, Leather Armor', NULL),
(88, 'Fisher', 1, 4, 15, 25, 232, 'Swimming', 60, NULL, 3, NULL, 1, 912, 3, 'Cast a wide net! You make an honest living doing the job that your grandparents did.', 'Harpoon, Dagger, Kelp Armor', NULL),
(89, 'Kadji', 1, 10, 15, 21, 130, NULL, 131, NULL, 273, 'Tawas', 1, 912, 7, 'Also known as a clever person, you know the basics of magic, curses, and mystical protections.', 'Teak Rod, Pedalaman Robe', NULL),
(90, 'Kaimahi Kohatu', 1, 4, 13, 24, 389, NULL, 21, NULL, 27, NULL, 1, 912, 6, 'Metal is rare on the Furanthur Isles. Stone weapons can be much sharper, but it takes a great deal of skill to use and to maintain them. Also, weapons made of stone don\'t rust.', 'Knapped Greatsword, Knapped Pole, Knapped Sword, 3×Knapped Ax, Kelp Armor', NULL),
(91, 'Koa-Niho', 1, 4, 7, 13, 388, NULL, 21, NULL, 27, NULL, 1, 912, 6, 'A brave warrior who makes their own arms and armor in the traditions of the many who came before them', 'Olona Armor, Brux Sword, Brux Spear, 2×Brux Dagger', NULL),
(92, 'Lecanomancer', 1, 22, 25, 26, 29, NULL, 45, NULL, 15, 'Calabrese', 1, 913, 7, 'The Ferobian Academy specializes in training wizards to work on naval vessels: fighting fires, changing winds, purifying water, and the like.', 'Rod, Blue Robe', NULL),
(93, 'Merchant Captain', 1, 9, 14, 25, 33, NULL, 15, 'Calabrese', 375, NULL, 1, 913, 1, 'They say you make untold fortunes if you\'re willing to risk sailing to the ends of the earth. Let\'s see if you can prove them right.', 'Shortsword, Leather Armor', NULL),
(94, 'Missionary', 1, 1, 12, 25, 15, 'Calabrese', 16, NULL, 38, NULL, 1, 913, 7, 'There are so many who have yet to hear the word of Helloise and to understand the rewards of heaven!', 'Electrum Staff, White Robe', NULL),
(95, 'Pirate Captain', 1, 1, 12, 25, 19, NULL, 7, NULL, 27, NULL, 1, 913, 4, 'Strike the colors and fire the guns. Your due is the plunder in the holds of those wretched colonials. No god or law, just the loyalty of your crew must see you through to victory.', 'Shortsword, Leather Armor', NULL),
(96, 'Quartermaster', 1, 1, 15, 25, 33, NULL, 19, NULL, 3, NULL, 1, 913, 3, 'Essential to the operation of any ship, you keep track of the resources on the ship: ammunition, food, and (most importantly) money.', 'Shortsword, Leather Armor', NULL),
(97, 'Settler', 1, 4, 15, 25, 21, NULL, 3, NULL, 27, NULL, 1, 913, 6, 'You\'ve come from a faraway place to make a new home. Don\'t let bandits and privateers think that you and yours are defenseless.', 'Pitchfork, Dagger, Leather armor', NULL),
(98, 'Silat Mystic', 1, 2, 7, 21, 130, NULL, 131, NULL, 273, 'Tawas', 1, 914, 7, 'You have mastered techniques for increasing your personal energy, both for casting spells and for bare-handed combat', 'Teak Rod, Pedalaman Robe', NULL),
(99, 'Silat Warrior', 1, 2, 7, 11, 59, NULL, 21, NULL, 27, NULL, 1, 914, 6, 'You have trained yourself to fight without weapons. Each tribe has their own fighting style, but you\'re pretty sure that yours is the best.', 'Dagger, 3', NULL),
(100, 'Tabokaikai', 1, 7, 13, 22, 383, NULL, 21, NULL, 27, NULL, 1, 914, 6, 'You are no stranger to the art of war. You are a master of coastal and island combat, especially at close quarters.', 'Taiaha, 3×Throwing Sticks, Wooden Shield, Katabara Armor', NULL),
(101, 'Artisan', 1, 1, 4, 14, 55, NULL, 33, NULL, 15, 'Zhongwén', 4, 450, 3, 'Every Gông Jiàng dreams of being the best at their trade.', 'Leather armor (d6), book of crafting', NULL),
(102, 'Ascetic (Zhongguo)', 1, 1, 2, 21, 44, NULL, 15, 'Zhongwen', 285, NULL, 4, 450, 1, 'A Yinshi who has taken vows of poverty and the like to improve their spirituality. Most learn martial arts only for meditation ... but some are warriors of mythic legend', 'Leather armor (d6), Copy of The Empty-Hand Methods', NULL),
(103, 'Assassin', 1, 2, 13, 20, 59, NULL, 23, NULL, 49, NULL, 4, 450, 4, 'The paranoid see them everywhere.\nAnd you always see one in every mirror.', 'Leather armor (d6), dagger (Damage +1) change of clothes', NULL),
(104, 'Begger (Zhongguo)', 1, 14, 15, 20, 49, NULL, 19, NULL, 94, NULL, 4, 450, 4, 'A pitiable sort who lives hand to mouth, a Qǐ Gài is always looking for a handout.', 'Leather armor (d6), Copy of The Empty-Hand Methods', NULL),
(105, 'Boxer', 1, 1, 2, 7, 59, NULL, 15, 'Zhongwen', 27, NULL, 4, 450, 6, 'Yihe Wu believe that through training, diet, martial arts, andprayer, they might perform extra-ordinary feats.', 'Leather armor (d6), Copy of The Empty-Hand Methods', NULL),
(106, 'Braggart', 1, 2, 7, 16, 21, NULL, 309, NULL, 27, NULL, 4, 450, 6, 'There’s often one Zhàn Pa whos bark is far worse than their bite.', 'Leather armor (d6), fancy haircut', NULL),
(107, 'Brigand', 1, 7, 13, 23, 59, NULL, 21, NULL, 27, NULL, 4, 451, 6, 'Unlike some thieves, who are forced into a life of crime out of desperation, Tu Fei have formidable arms and armor, with sophisticated networks and domination over large swaths of land.', 'Leather armor (d6), large sack', NULL),
(108, 'Brute', 1, 2, 7, 16, 59, NULL, 81, NULL, 27, NULL, 4, 451, 6, 'Sometimes, you can solve a problem by bringing in a really big warrior. Jù Rén can ask for up to double what other mercenaries get paid.', 'Leather armor (d6), cestus (Damage +1, Parry d12)', NULL),
(109, 'Bureaucrat', 1, 1, 9, 10, 237, NULL, 15, 'Zhongwén', 57, NULL, 4, 451, 1, 'Throughout Zho–ngguo’s government are the Liao, readers of the rules, recorders of the law, and various other bureaucrats who preside over the day-to-day affairs of the noble households.', 'Leather armor (d6), book of laws, writing kit', NULL),
(110, 'Changes Wizard', 1, 1, 10, 21, 215, NULL, 216, NULL, 15, 'Zhongwen', 4, 451, 7, 'Fah Shih observe how nature interacts with itself, and they use that knowledge to their advantage, with magic so subtle that it might not even be observed', 'Robes, rod, wand', NULL),
(111, 'Debo Shih', 1, 2, 7, 21, 273, 'Immortal Magic', 15, 'Zhongwen', 27, NULL, 4, 452, 6, 'A warrior who studies both the martial and the magical arts', 'Leather Armor (d6), writing kit', NULL),
(112, 'Destitute', 1, 8, 14, 19, 62, NULL, 49, NULL, 19, NULL, 4, 452, 4, 'What terrible misfortune must have cursed the Liú Làng to live hand to mouth, wandering the landscape without a home?', 'Cotton armor (d4), empty wooden bowl', NULL),
(113, 'Doctor', 1, 1, 10, 15, 48, NULL, 15, 'Zhongwén', 72, NULL, 4, 452, 1, 'A good Y–ı Jia– will know acupuncture, moxa burning, and several other techniques to treat injuries and sickness.', 'Cotton armor (d4), 117 acupuncture needles', NULL),
(114, 'Escort', 1, 2, 14, 15, 20, NULL, 59, NULL, 98, NULL, 4, 452, 6, 'A Biao Ke guards his target throughout duration of a given trip. Not only must they rely on their fighting abilities, they have to be able to negotiate their way out of troubles too.', 'Leather armor (d6), Staff (Damage +1, Parry d12)', NULL),
(115, 'Flamboyant', 1, 2, 7, 16, 34, NULL, 59, NULL, 27, NULL, 4, 453, 6, 'The dragon flies, the phoenix dances, and the Lóng Fêi Fèng Wu^ does everything larger than life.', 'Leather armor (d6), jade hairclip', NULL),
(116, 'Immortal Sage', 1, 1, 12, 21, 228, 'Shen Xian', 15, 'Zhongwén', 273, 'Immortal Magic', 4, 453, 1, 'A student of powerful but exhausting magic, the Shén Xiân learn magic more useful for state-craft than for combat.', 'Leather armor (d6), writing kit', NULL),
(117, 'Irregular', 1, 4, 7, 23, 21, NULL, 3, NULL, 27, NULL, 4, 453, 6, 'A Mín B^i ng is a commoner who sometimes has to serve in a military capacity, perhaps as a guard, militia, or police.', 'Leather armor (d6), Shortsword (Damage +1), Wooden shield (Cover d8)', NULL),
(118, 'Lancer', 1, 7, 13, 25, 88, NULL, 21, NULL, 27, NULL, 4, 453, 6, 'Ge Shou are elite soldiers who are able to leap off fast moving chariots or wagons and take advantage of the speed to strike at their enemies.', 'Leather armor (d6), Lance (Damage +1, Tilting)', NULL),
(119, 'Lobbyist', 1, 1, 10, 14, 56, NULL, 15, 'Zhongwén', 68, NULL, 4, 454, 1, 'Shu-Ki loves nothing more than of battles of tongues. Nothing amuses them more than to see confusion on their opponents’ faces. Of course, Shu-Ki knows what is best for you.', 'Cotton armor (d4), book', NULL),
(120, 'Method Archer', 1, 7, 15, 17, 15, 'Zhongwén', 211, NULL, 27, NULL, 4, 454, 6, 'The war-bands of Zho–ngguo prefer to hire their Gông Jiàn Sho˘u in large groups, to rain a storm of arrows upon their foes.', 'Leather armor (d6), Longbow, thumb guard', NULL),
(121, 'Minister', 1, 1, 14, 16, 58, NULL, 15, 'Zhongwén', 26, NULL, 4, 454, 5, 'The government of Zho–ngguo does not run itself. Many Buzhang have their positions as favors granted because of relatives, bribes, or even their own skill or guile.', 'Leather armor (d6), Copy of The Empty-Hand Methods', NULL),
(122, 'Money-Lender', 1, 1, 4, 14, 33, NULL, 237, NULL, 15, 'Zhongwén', 4, 454, 1, 'As the wealth of the citizenry increases, so do people’s debts. The unpopular Ye Jie lends money at huge interest rates ... until the loan’s interest builds up and the collateral becomes theirs.', 'Cloth armor (d4), knife', NULL),
(123, 'Mugger', 1, 2, 9, 16, 59, NULL, 21, NULL, 27, NULL, 4, 455, 6, 'It is not wise to wander through the city streets alone after dark. Some Qiang Dao will take your valuables and flee ... but others would sooner kill any witnesses to their crimes.', 'Leather armor (d6), stolen fruit', NULL),
(124, 'Nomad', 1, 4, 8, 15, 97, NULL, 94, NULL, 3, NULL, 4, 455, 3, 'Living outside cities, the Di know nothing of finer civilization but rather live day to day. Almost all nomads are friendly barbarians — the ones who plunder and attack are Bandits.', 'Leather armor (d6), Sling (Damage +1), bedroll', NULL),
(125, 'Peasant', 1, 4, 8, 15, 55, NULL, 49, NULL, 3, NULL, 4, 455, 3, 'Almost everyone in Zho–ngguo are simple Nóng Fu who work the land for their masters.', 'Leather armor (d6), Rake (Damage +3 Weak)', NULL),
(126, 'Perfect Knight', 1, 1, 7, 14, 155, NULL, 110, 'Flute', 27, NULL, 4, 455, 5, 'A Jun Zi is both scholar and a warrior — to maintain composure at all times, to discuss philosophy, to play a musical instrument, and to defend against physical aggression.', 'Leather armor (d6), Longsword (Damage +2), flute', NULL),
(127, 'Procurer', 1, 5, 9, 10, 37, NULL, 33, NULL, 19, NULL, 4, 456, 4, 'A professional Hei Dao believes that they can do anything faster and better than the government. The best know all the brothels, drinking houses, drug dens, and other places of iniquity', 'Leather armor (d6), knife', NULL),
(128, 'Purity Wizard', 1, 1, 15, 21, 15, 'Zhongwén', 209, NULL, 208, NULL, 4, 456, 7, 'The most ancient form of magic, the art practiced by Shén Qing existed before written text. Purity Magic works with personal nature, either enriching the pure or punishing the wicked.', 'Robes', NULL),
(129, 'Racketeer', 1, 2, 7, 16, 59, NULL, 33, NULL, 19, NULL, 4, 456, 4, 'A thug who extorts money from local businesses. Feitu-jituan threaten locals with vandalism and violence if they do not meet their demands of money or favors.', 'Leather armor (d6), Club (Damage +2 Weak)', NULL),
(130, 'Scribe', 1, 1, 4, 15, 55, NULL, 15, NULL, 31, NULL, 4, 456, 1, 'In the absence of regular schooling and inexpensive printing, Literacy: Zhongwén is largely unknown. Wen Li Scribes are necessary for holding any sort of court, legal or noble.', 'Cotton armor (d4), book, writing kit', NULL),
(131, 'Soothsayer', 1, 1, 19, 21, 98, NULL, 15, 'Zhongwen', 31, NULL, 4, 457, 1, 'It is a common belief that omens that foretell the future are everywhere and can be interpreted by those who can read the signs. A Xianjianzhe can read the signs to good effect.', 'Cotton armor (d4), good luck charm', NULL),
(132, 'Spirit Hunter', 1, 2, 7, 21, 59, NULL, 21, NULL, 27, NULL, 4, 457, 6, 'It is a common belief that omens that foretell the future are everywhere and can be interpreted by those who can read the signs. A Xianjianzhe can read the signs to good effect.', 'Cotton armor (d4), good luck charm', NULL),
(133, 'Storyteller', 1, 1, 9, 16, 15, NULL, 68, NULL, 110, 'Story-Telling', 4, 457, 1, 'Yi Ren brings joys and pleasures to her fellows. The beautiful, the tragic, the comic, the valiant, the villainous of Zho–ngguo all come alive through painting, poetry, singing, or dance.', 'Cotton armor (d4), staff (Damage +1, Parry d12)', NULL),
(134, 'Sword Dancer', 1, 7, 13, 16, 188, NULL, 110, 'Dance', 182, NULL, 4, 457, 6, 'To a Jiàn-Nú, few can understand the thrill of being alive within flashes of sharp edges. They often claim that the ultimate weapon skill is to strike without drawing blood.', 'Silk armor (2d4), Martial Sword (Damage +2 Critical), Scholarly Sword (Damage +2 Impaling)', NULL),
(135, 'Tàoist Wizard', 1, 1, 7, 21, 108, NULL, 15, 'Zhongwen', 205, NULL, 4, 458, 7, 'Dào Shih observed how nature interacted with itself and thus became enlightened. Their belief is that all sentient beings should live in harmony with nature instead of dominating or destroying it.', 'Robes, Rod (Damage +2, Parry d12), Wand', NULL),
(136, 'Tax Collector', 1, 1, 10, 16, 33, NULL, 15, 'Zhongwen', 57, NULL, 4, 458, 1, 'Probably the most unpopular person in the empire, the Ye Chouji comes to take what is the Emperor’s due.', 'Cotton armor (d4), large sack, ledger, writing kit', NULL),
(137, 'Trader', 1, 1, 10, 14, 58, NULL, 33, NULL, 15, 'Zhongwen', 4, 458, 3, 'With the rise of the middle class and the popularity of coinage, the Ye Gu has become a common occupation. Traders can be a single operation, or the owner of a complex caravan.', 'Leather armor (d6), Hammer (Damage +2 Weak), large sack full of Cheap and Average goods', NULL),
(138, 'Tomb Defender', 1, 2, 6, 7, 59, NULL, 90, NULL, 27, NULL, 4, 458, 6, 'Since the passing of the first sage king, a group of loyal followers called Líng-mù Shí has existed, dedicated to maintaining the final resting-place from deterioration.', 'Leather armor (d6), Torch (Damage +0 Weak, On Fire)', NULL),
(139, 'Vagrant Warrior', 1, 7, 13, 23, 9, NULL, 228, 'Vagrant Warriors', 27, NULL, 4, 458, 6, 'Wu Xià wander in search of perfection: to become the greatest at fighting with one weapon. The greatest among them aspire to become master of all weapons.', 'Leather armor (d6), Longsword (Damage +2), Wooden Shield (Cover d8), Short bow (Damage +0 Critical)', NULL),
(140, 'Ascetic (Calabria)', 1, 1, 2, 21, 59, NULL, 15, NULL, 81, NULL, 6, 363, 1, 'A monk, nun, or other religious person who specializes in physical conditioning.', 'Cloth armor (d4), first aid kit, knife, holy symbol', NULL),
(141, 'Beguine', 1, 1, 10, 21, 146, NULL, 48, NULL, 276, NULL, 6, 363, 7, 'A blessed man or woman who uses their gifts to help others. Usually found in a Lutarist community, often has taken a vow of poverty.', 'Cloth Armor (d4), Staff (Damage +1, Parry d12)', NULL),
(142, 'Brehon', 1, 1, 14, 21, 56, NULL, 397, NULL, 398, NULL, 6, 363, 7, 'As far back as anyone can remember, the Phelan have had the Fenechas, their code of laws. It is the duty of the Brehona to interpret the law justly.', 'Sloe Rod (Damage +2, Parry d12), Leather armor (d6), knife, scales and balance, plumb line.', 'Requires: Language - Berla Feini'),
(143, 'Crusader', 1, 7, 13, 17, 15, NULL, 285, NULL, 27, NULL, 6, 363, 6, 'A religious devotee who fights for their faith.', 'Sloe Rod (Damage +2, Parry d12), Leather armor (d6), knife, first aid kit', NULL),
(144, 'Curraidh', 1, 1, 13, 21, 397, NULL, 398, NULL, 27, NULL, 6, 363, 7, 'Some say wizards are subtle and quick to anger. A Curraidh is brutal ... And swift to anger.', 'Sloe Rod (Damage +2, Parry d12), Leather armor (d6), knife, first aid kit', 'Requires: Language - Berla Feini'),
(145, 'Dabbler', 1, 1, 15, 21, 15, NULL, 273, NULL, 31, NULL, 6, 363, 1, 'Perhaps a rich person with an idle interest in magic, or just a person curious in the secrets of the universe, the Dabbler may eventually become a wizard.', 'Leather armor (d6), Staff (Damage +1, Parry d12), chapbook', NULL),
(146, 'Gelassenheiter', 1, 4, 8, 21, 49, NULL, 276, NULL, 285, NULL, 6, 364, 3, 'A devout religious person who believes in selflessness and living a simple life, above all else.', 'Cloth armor (d4), walking stick, holy symbol', NULL),
(147, 'Hermit', 1, 1, 8, 21, 276, NULL, 285, NULL, 94, NULL, 6, 364, 1, 'A religious devotee who lives out in the middle of nowhere, showing their faith by becoming removed from society.', 'Cloth armor (d4), first aid kit, knife, holy symbol', NULL),
(148, 'Hexanhammer', 1, 7, 13, 17, 146, NULL, 276, NULL, 27, NULL, 6, 364, 7, 'A Blessed who uses their spirits to help them defeat their foes. While some Hexenhammers use their powers for good, many become selfish and wrathful.', 'Leather armor (d6), Longbow (Damage +1 Critical), Mace (Damage +2), Wooden Shield (cover d8)', NULL),
(149, 'Initiate', 1, 1, 8, 21, 228, NULL, 276, NULL, 285, NULL, 6, 364, 1, 'The lowest ranking member of a cult. Strange cults tend to spring up in remote places - some of them earnest, others run by charlatans and unfortunate few that are crazy.', 'Cloth armor (d4), holy symbol', NULL),
(150, 'Inquisitor', 1, 10, 19, 21, 69, NULL, 15, NULL, 27, NULL, 6, 364, 6, 'In Avoirdupois and Bisclavret lands, special agents root out misbelievers who insist on breaking the law about their religious worship.', 'Leather armor (d6), Mace (Damage +2), holy symbol, religious pamphlets, chapbook about magic', NULL),
(151, 'Midwife', 1, 1, 10, 12, 46, NULL, 276, NULL, 3, NULL, 6, 364, 1, 'A country doctor, almost always female, who specializes in delivering babies and folk medicine.', 'Cloth armor (d4), first aid kit, holy vestments, holy symbol', NULL),
(152, 'Oracle', 1, 1, 15, 21, 146, NULL, 98, NULL, 276, NULL, 6, 365, 7, 'A blessed man or woman with the gift of prophecy. With proper training, they can see into the future.', 'Leather armor (d6), Staff (Damage +1, Parry d12)', NULL),
(153, 'Ordinary', 1, 1, 12, 21, 236, 'Magniloqquentia', 15, NULL, 65, 's\'Allumer', 6, 365, 1, 'A priest or priestess who has been ordained by a Church of s\'Allumer. They can marry others, sanctify events, etc.', 'Cloth armor (d4), religious pamphlet, holy vestments, holy symbol.', NULL),
(154, 'Ovate', 1, 1, 15, 21, 98, NULL, 397, NULL, 398, NULL, 6, 365, 7, 'They say that when commoners don\'t understand what you say, they make you an Ovate. When the Ovates can\'t understand you, they make you a Master Ovate.', 'Sloe Rod (Damage +2, Parry d12), Leather armor (d6), knife, inscrutable object.', 'Requires: Language - Berla Feini'),
(155, 'Pilgrim', 1, 1, 8, 9, 44, NULL, 97, NULL, 285, NULL, 6, 365, 1, 'A religious practitioner who takes a journey to someplace far away, perhaps to visit holy sites or to find enlightenment.', 'Cloth armor (d4), first aid kit, holy vestments, holy symbol', NULL),
(156, 'Postulant', 1, 1, 8, 21, 14, NULL, 236, 'Magniloqquentia', 15, NULL, 6, 365, 3, 'A practitioner of White Magic who seeks to join an order. Many tests may be required before they rise to the ranks of Priest or Priestess.', 'Cloth armor (d4), first aid kit, holy vestments, holy symbol', NULL),
(157, 'Preacher', 1, 1, 16, 21, 97, NULL, 68, NULL, 285, NULL, 6, 365, 1, 'Someone who wanders from place to place, spreading the word about religion, seeking to convert more lost souls.', 'Cloth armor (d4), first aid kit, holy vestments, holy symbol', NULL),
(158, 'Questor', 1, 1, 8, 14, 14, NULL, 15, NULL, 57, NULL, 6, 366, 1, 'A collector of church tithes, the Questor is both welcomed and avoided by the populace. The potential for corruption is a constant fear for church officials.', 'Leather armor (d6), Dagger (Damage +1), holy vestments, holy symbol, ledger to track tithes, scale and balance', NULL),
(159, 'Sacristan', 1, 4, 8, 21, 55, 'Forestry', 276, NULL, 285, NULL, 6, 366, 3, 'One who maintains the Sacred Groves of Lutara. Only the devout are permitted.', 'Cloth armor (d4), Dagger (Damage +1), holy symbol', NULL),
(160, 'Sectary', 1, 1, 5, 21, 15, NULL, 49, NULL, 285, NULL, 6, 366, 1, 'A self-styled cleric who practices an unpopular religion. In many places in Calabria, some religions are banned by law.', 'Cloth armor (d4), Dagger (Damage +1), holy symbol, unpopular religion\'s bible', NULL),
(161, 'Sexton', 1, 1, 4, 21, 14, NULL, 55, NULL, 3, NULL, 6, 366, 3, 'A custodian of the church. The larger cathedrals have dozens of Sextons on staff.', 'Cloth armor (d4), knife, holy symbol, tools of the trade, ring of keys', NULL),
(162, 'Sibyl', 1, 8, 19, 21, 146, NULL, 245, NULL, 276, NULL, 6, 366, 7, 'A woman blessed by the spirits. She may be a practicing Lutarist, or a reincarnation of a Hierach, or just lucky (or unlucky) enough to have the gift.', 'Leather armor (d6), Staff (Damage +1, Parry d12)', 'Requires: Must be female'),
(163, 'Vidame', 1, 7, 13, 21, 20, NULL, 98, NULL, 21, NULL, 6, 366, 6, 'A protector of a blessed priestess.', 'Leather and cloth armor (d4, d6), Wooden Shield (cover d8), Half-Spear (Damage +2), first aid kit', NULL),
(164, 'Alchemist', 1, 1, 4, 24, 123, NULL, 15, NULL, 31, NULL, 3, 742, 1, 'You make strange chemicals in your lab, both for harm and healing. Try not to identify too many chemicals by tasting them.', 'Leather armor (d6), 6 bottles of Aqua Fortis, 6 bottles of Aqua Vitae, 12 bottles of medicine (quack), 6 bottles of medicine (good), acid-stained apron', NULL),
(165, 'Almaghnatisia', 1, 10, 12, 14, 401, NULL, 39, NULL, 15, 'Deltan', 3, 742, 7, 'Since the Cognoscente books are written anonymously, it’s not clear where their magical arts were created, though many claim that it began within Akoma.', 'Leather armor (d6), Quicksilver Rod (Damage +1 Critical)', NULL),
(166, 'Badjaduya', 1, 1, 15, 21, 29, NULL, 45, 'Air', 15, 'Deltan', 3, 742, 7, 'The celebrated “Wind Wizards” of the Emirates. A Dunwasser alumnus might call their magic “primitive.” They prefer the term “traditional.”', 'Yellow Robe, Oak Rod (Damage +1 Critical)', NULL),
(167, 'Black Angel', 1, 10, 19, 21, 49, NULL, 19, NULL, 94, NULL, 3, 742, 1, 'One who studies forbidden arts in order to hunt down evil necromancers and the walking dead.', 'Cloth armor (d4), knife, battered notebook', NULL),
(168, 'Dastani', 1, 1, 15, 19, 61, NULL, 364, NULL, 94, NULL, 3, 743, 1, 'A navigator of the great desert, using only the stars as their guide. (Since, well, everything else is pretty bleak.)', 'Cloth armor (d4), Staff (Damage +1), comfortable hat', NULL),
(169, 'Dervish', 1, 8, 16, 21, 110, 'Dance', 285, 'Malachism', 94, NULL, 3, 743, 1, 'These mystics bridge the gap between the common man and the mysteries of Malachism.', 'Cloth armor (d4), Staff (Damage +1), comfortable hat', NULL),
(170, 'Djed-Kakim', 1, 5, 16, 21, 399, NULL, 15, 'Deltan', 387, NULL, 3, 743, 7, 'Tolerated at best, those who would dare pursue necromancy should know better than to speak of their magic to the commoners.', 'Black Robes, Brass Staff (Damage +1 Critical), change of clothes for going out in public society', NULL),
(171, 'Hospitaller', 1, 1, 13, 25, 72, NULL, 285, 'Penitence', 27, NULL, 3, 743, 6, 'These seafaring healer-knights are based out of the Honey Isle citadels.', 'Leather armor d6, Longsword (Dmg +2), wooden shield (Cover d8)', NULL),
(172, 'Jannisary', 1, 8, 17, 23, 391, NULL, 21, NULL, 27, NULL, 3, 743, 6, 'Recruited from the Anatolians’ vassal states via the infamous Tribute in Blood, these elites are among the world’s best infantry.', 'Leather armor d6, Longsword (Dmg +2), Jezail (Dmg +2 Slaying), uniform', NULL),
(173, 'Medjey', 1, 7, 13, 23, 386, NULL, 21, NULL, 27, NULL, 3, 743, 6, 'With their unusual weapons and armor, these mercenaries for hire are unique to Akoma. Most frequently seen the the Deltan Valley.', 'Leather armor d6, Kopesh (Dmg +4 Weak Critical), Metal Shield (Cover d8)', NULL),
(174, 'Qanundari', 1, 10, 17, 19, 391, NULL, 21, NULL, 27, NULL, 3, 744, 6, 'The soldiers and policemen of the Emirates, these warriors dispense quick justice and protect the oases and property of their tribes.', 'Leather armor d6, Longsword (Dmg +2), Jezail (Dmg +2 Slaying), uniform', NULL),
(175, 'Qäs', 1, 1, 12, 21, 14, NULL, 15, 'Deltan', 400, NULL, 3, 744, 7, 'As part of the aggressive modernism of the Anatolians, these priests are encouraged to spread the light of s’Allumer with the state-approved religion of Malachism', 'White Robes, Electrum Rod (Dmg +1 Critical)', NULL),
(176, 'Sportster', 1, 2, 8, 24, 17, NULL, 91, NULL, 3, NULL, 3, 744, 3, 'Subjects of the Anatolian Empire enjoy their bread and circuses. Team sports and ball games are popular in the cities.', 'Cloth armor d4, nice scarf', NULL),
(177, 'Tazekar', 1, 1, 15, 21, 146, NULL, 276, NULL, 394, NULL, 3, 744, 7, 'A mystic of the Great Desert, who can read the stars and knows how to interpret what the divine wants. (This career requires Book of Mysteries to use.)', 'Leather armor d6, Staff (Dmg +1)', NULL),
(178, 'Vizier', 1, 1, 15, 23, 26, NULL, 68, NULL, 7, NULL, 3, 744, 1, 'A high-ranking advisor, usually for matters of state or for war. Some are to be trusted, others have their own schemes.', 'Leather armor d6, Dagger (Dmg +1), turban, detailed map of their local area', NULL),
(179, 'Warlord', 1, 7, 12, 16, 26, NULL, 68, NULL, 7, NULL, 3, 744, 1, 'In the remote and provincial corners of Akoma, some people are raised to be leaders of their tribe, town, or community.', 'Leather armor d6, Longsword (Dmg +2), turban', NULL),
(180, 'Warlock (Earth)', 1, 7, 13, 21, 399, 'Earth', 29, NULL, 15, 'Calabrese', 5, 36, 7, 'A wizard who has passed over theory and philosophy to train to use elemental magic for battle.', 'Shortsword (Damage +1 Impaling), Leather armor (d6)', NULL),
