--
-- Table structure for table `careers`
--

CREATE TABLE `careers` (
  `id` int NOT NULL,
  `career_name` text,
  `career_type` int DEFAULT NULL,
  `career_skill_one` int DEFAULT NULL,
  `career_skill_two` int DEFAULT NULL,
  `career_skill_three` int DEFAULT NULL,
  `career_gift_one` int DEFAULT NULL,
  `career_gift_one_choice` text,
  `career_gift_two` int DEFAULT NULL,
  `career_gift_two_choice` text,
  `career_gift_three` int DEFAULT NULL,
  `career_gift_three_choice` text,
  `career_source_book` int DEFAULT NULL,
  `pg_no` int DEFAULT NULL,
  `career_archtype` int DEFAULT NULL,
  `career_description` text,
  `career_trappings` text,
  `requires` varchar(80) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

